WITH RECURSIVE shared_tree AS (
    SELECT * FROM sys_file
    WHERE id = #{rootId}
    AND space_type = #{spaceType}
    AND space_id = #{spaceId}
    AND is_directory = 1
    AND in_recycle_bin = 0
    AND is_deleted = 0
    UNION ALL
    SELECT f.* FROM sys_file f
    INNER JOIN shared_tree t ON f.parent_id = t.id
    WHERE f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.is_directory = 1
    AND f.in_recycle_bin = 0
    AND f.is_deleted = 0
)
SELECT * FROM shared_tree
WHERE id = #{directoryId}
