AND space_id = #{spaceId}
AND is_deleted = 0
ORDER BY id

WITH RECURSIVE descendants AS (
    SELECT * FROM sys_file
    WHERE id = #{rootId}
    AND space_type = #{spaceType}
    AND space_id = #{spaceId}
    AND is_deleted = 0
    UNION ALL
    SELECT f.* FROM sys_file f
    INNER JOIN descendants d ON f.parent_id = d.id
    WHERE f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND (
        COALESCE(d.in_recycle_bin, 0) = 0
        OR (f.in_recycle_bin = 1 AND COALESCE(f.recycle_root, 0) = 0)
    )
    AND f.is_deleted = 0
)
SELECT * FROM descendants WHERE id != #{rootId}

WITH RECURSIVE descendants AS (
    SELECT * FROM sys_file
    WHERE id = #{rootId}
    AND space_type = #{spaceType}
    AND space_id = #{spaceId}
    AND in_recycle_bin = 0
    AND is_deleted = 0
    UNION ALL
    SELECT f.* FROM sys_file f
    INNER JOIN descendants d ON f.parent_id = d.id
    WHERE f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.in_recycle_bin = 0
    AND f.is_deleted = 0
)
SELECT * FROM descendants WHERE id != #{rootId}

mapper.update:
WITH RECURSIVE descendants AS (
    SELECT f.id, CONCAT(#{parentFullPath}, ',', f.id) AS new_full_path
    FROM sys_file f
    WHERE f.parent_id = #{rootId}
    AND f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.is_deleted = 0
    UNION ALL
    SELECT f.id, CONCAT(d.new_full_path, ',', f.id)
    FROM sys_file f
    INNER JOIN descendants d ON f.parent_id = d.id
    WHERE f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.is_deleted = 0
)
UPDATE sys_file s
INNER JOIN descendants d ON s.id = d.id
SET s.full_path = d.new_full_path

WITH RECURSIVE descendants AS (
    SELECT f.id FROM sys_file f
    WHERE f.parent_id = #{rootId}
    AND f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.in_recycle_bin = 0
    AND f.is_deleted = 0
    UNION ALL
    SELECT f.id FROM sys_file f
    INNER JOIN descendants d ON f.parent_id = d.id
    WHERE f.space_type = #{spaceType}
    AND f.space_id = #{spaceId}
    AND f.in_recycle_bin = 0
    AND f.is_deleted = 0
)
UPDATE sys_file s
INNER JOIN descendants d ON s.id = d.id
SET s.in_recycle_bin = 1,
    s.recycle_root = 0,
    s.deleted_at = #{deletedAt},
    s.expire_at = #{expireAt}

UPDATE sys_file
SET in_recycle_bin = 1,
    recycle_root = 1,
    deleted_at = #{deletedAt},
    expire_at = #{expireAt},
    deleted_by = #{deletedBy},
    update_time = #{deletedAt}
WHERE id = #{rootId}
AND space_type = #{spaceType}
AND space_id = #{spaceId}
AND in_recycle_bin = 0
AND is_deleted = 0

UPDATE sys_file
SET is_deleted = 1,
    update_time = NOW()
WHERE space_type = #{spaceType}
AND space_id = #{spaceId}
AND is_deleted = 0

